 /* --- Chat view --- */
 .chat-view {
   display: flex;
-  flex-direction: column;
   height: 100%;
   overflow: hidden;
 }

-.chat-context-bar {
+/* Chat sidebar (channels / DMs) */
+.chat-sidebar {
+  width: 220px;
+  flex-shrink: 0;
+  display: flex;
+  flex-direction: column;
+  border-right: 1px solid var(--border);
+  background: var(--chat-sidebar-bg);
+  overflow: hidden;
+}
+
+.chat-sidebar-section {
+  padding: 10px 10px 6px;
+}
+
+.chat-sidebar-heading {
+  font-size: 10px;
+  font-weight: 700;
+  text-transform: uppercase;
+  letter-spacing: 0.08em;
+  color: var(--text-tertiary);
+  padding: 0 6px 6px;
+}
+
+.chat-sidebar-list {
+  display: flex;
+  flex-direction: column;
+  gap: 1px;
+}
+
+.chat-sidebar-scroll {
+  flex: 1;
+  overflow-y: auto;
+}
+
+.chat-sidebar-item {
   display: flex;
   align-items: center;
   gap: 8px;
-  padding: 8px 20px;
+  width: 100%;
+  padding: 6px 10px;
+  border-radius: 6px;
+  border: none;
+  background: transparent;
+  color: var(--text-secondary);
+  font-size: 13px;
+  font-weight: 500;
+  text-align: left;
+  cursor: pointer;
+  transition: background 80ms ease;
+  white-space: nowrap;
+  overflow: hidden;
+  text-overflow: ellipsis;
+}
+
+.chat-sidebar-item:hover {
+  background: var(--chat-sidebar-hover);
+  color: var(--text);
+}
+
+.chat-sidebar-item.active {
+  background: var(--chat-sidebar-active);
+  color: var(--text);
+  font-weight: 600;
+}
+
+.chat-sidebar-icon {
+  font-size: 14px;
+  flex-shrink: 0;
+  width: 18px;
+  text-align: center;
+  color: var(--text-tertiary);
+}
+
+.chat-sidebar-item.active .chat-sidebar-icon {
+  color: var(--accent);
+}
+
+.chat-sidebar-label {
+  overflow: hidden;
+  text-overflow: ellipsis;
+}
+
+.chat-sidebar-badge {
+  margin-left: auto;
+  font-size: 10px;
+  font-weight: 600;
+  color: var(--text-tertiary);
+}
+
+/* Chat main area (messages + composer) */
+.chat-main {
+  flex: 1;
+  display: flex;
+  flex-direction: column;
+  overflow: hidden;
+  min-width: 0;
+}
+
+.chat-channel-header {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+  padding: 10px 20px;
   border-bottom: 1px solid var(--border);
   background: var(--bg-surface);
   flex-shrink: 0;
-  flex-wrap: wrap;
 }

-.conv-chip {
-  padding: 4px 12px;
+.chat-channel-name {
+  font-size: 14px;
+  font-weight: 700;
+  color: var(--text);
+}
+
+.chat-channel-kind {
+  font-size: 11px;
+  color: var(--text-tertiary);
+  padding: 2px 8px;
+  border-radius: 4px;
+  background: var(--bg-inset);
+}
+
+.chat-thread-chips {
+  display: flex;
+  align-items: center;
+  gap: 4px;
+  margin-left: auto;
+}
+
+.thread-chip {
+  padding: 3px 10px;
   border-radius: 999px;
-  font-size: 12px;
+  font-size: 11px;
   font-weight: 500;
   border: 1px solid var(--border);
   background: transparent;
